        "bd0a1939eca6466bb01262550eed91cf": {
          "id": "bd0a1939eca6466bb01262550eed91cf",
          "stepType": "ScriptOutput",
          "name": "Lookup_Customer",
          "output_type": "single_part",
          "script": "(function execute() {\n\n    var gr = new GlideRecord('u_churn_customer');\n\n    gr.addQuery(\n        'u_company_name',\n        vaVars.customer_company_name\n    );\n\n    gr.query();\n\n    if (gr.next()) {\n\n        vaVars.customer_found = \"true\";\n\n        vaVars.company =\n        gr.u_company_name.toString();\n\n        vaVars.risk_score =\n        gr.u_churn_risk_score.toString();\n\n        vaVars.risk_category =\n        gr.u_risk_category.toString();\n\n        vaVars.open_tickets =\n        gr.u_open_tickets.toString();\n\n        vaVars.nps =\n        gr.u_nps_score.toString();\n\n        vaVars.ai_explanation =\n        gr.u_ai_risk_explanation.toString();\n\n        return \"Customer found\";\n\n    }\n\n    else {\n\n        vaVars.customer_found = \"false\";\n\n        return \"Customer not found\";\n    }\n\n})();",
          "applicability": {
            "value": "",
            "mode": "query"
          }
        },
